using Forge.Core.Entities;
using Forge.Core.Enums;
using Forge.Data.Context;

using Serilog;

namespace Forge.Api.Data.TrainingContent;

public class DashboardTraining : TrainingContentBase
{
    public DashboardTraining(AppDbContext db, Dictionary<string, int> slugMap) : base(db, slugMap) { }

    public override async Task SeedAsync()
    {
        // ── Overview (Article) ───────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Dashboard Overview",
            Slug = "dashboard-overview",
            Summary = "What the Dashboard shows, how widgets work, and how to customize your layout for daily productivity.",
            ContentType = TrainingContentType.Article,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 1,
            AppRoutes = """["/dashboard"]""",
            Tags = """["dashboard","widgets","home"]""",
            ContentJson = """{"body":"## Dashboard Overview\n\nThe Dashboard is your home screen — the first thing you see after logging in. It gives you an at-a-glance summary of your day: tasks due, jobs by stage, orders in progress, and planning cycle status. Everything is organized into draggable widgets that you can rearrange to match your workflow.\n\n### Widget-Based Layout\n\nThe Dashboard uses a grid layout powered by gridstack. Each piece of information lives in its own widget card. You can drag widgets to rearrange them, and your layout is saved to your user preferences so it persists across sessions and devices. In edit mode you can add or remove widgets from the catalog.\n\n### Core Widgets\n\n**Today's Tasks:** Shows your assigned jobs sorted by priority (overdue first). Overdue jobs are highlighted so you can see what needs immediate attention. Click any job to open its detail dialog.\n\n**Jobs by Stage:** A horizontal bar chart showing how many jobs sit in each board stage, so you can see where work is concentrated.\n\n**Open Orders:** A summary of open sales orders with the total count plus a breakdown by Confirmed, In Production, and Partially Shipped. Gives you a quick sense of the pipeline without leaving the dashboard.\n\n**Cycle Progress:** Shows your current planning cycle's completion percentage. The progress label shows completed vs total entries, and a status chip flags when the cycle is overdue, helping you prioritize.\n\n**End of Day:** A prompt to capture your Top 3 for tomorrow. Type your priorities and save them; once saved the widget shows your response with an Edit button.\n\n**Margin Summary:** Average margin percentage plus revenue, cost, and margin totals for recent jobs (standalone accounting mode only).\n\n### Getting Started Banner\n\nNew users see a Getting Started banner that tracks onboarding progress — creating your first job, adding a customer, setting up track types, and exploring reports. The banner disappears once enough onboarding steps are complete; you can also dismiss it manually.\n\n### Other Widgets\n\nThe widget catalog also includes Team Load (per-person workload bars), Deadlines (upcoming due dates), Activity (recent activity feed), Action Items (follow-up tasks you can complete or dismiss), and Inventory Snapshot (part counts and low-stock alerts). Available widgets depend on which capabilities your install has enabled.\n\n### Loading and Performance\n\nThe Dashboard loads with a global loading overlay (LoadingService) because it fetches data from multiple endpoints simultaneously. Once all widgets have their data, the overlay clears and you see the full dashboard at once — no partial loading or flickering.","sections":[]}"""
        });

        // ── Walkthrough ──────────────────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Dashboard — Guided Tour",
            Slug = "dashboard-walkthrough",
            Summary = "A guided tour of the Dashboard: widgets, task list, jobs by stage, open orders, cycle progress, and layout customization.",
            ContentType = TrainingContentType.Walkthrough,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 2,
            AppRoutes = """["/dashboard"]""",
            Tags = """["dashboard","walkthrough"]""",
            ContentJson = """{"appRoute":"/dashboard","startButtonLabel":"Tour Dashboard","steps":[{"element":".dashboard-content","popover":{"title":"Dashboard Content Area","description":"Your dashboard is built from draggable widgets. Grab any widget by its header and drag it to a new position. Your layout is saved automatically to your user preferences — it'll look the same next time you log in, even from a different device.","side":"top"}},{"element":".dashboard-kpis","popover":{"title":"KPI Overview","description":"Key performance indicators displayed as compact chips at the top of the dashboard. Shows your active job count, overdue count, and total hours for a quick status check. These chips appear when the jobs module is enabled.","side":"bottom"}},{"element":"app-page-header","popover":{"title":"Page Header & Controls","description":"The dashboard header with edit and ambient mode controls. Use these to customize your widget layout or toggle the ambient dashboard display.","side":"bottom"}},{"element":"app-dashboard-widget","popover":{"title":"Dashboard Widget","description":"Each widget in the grid shows a different piece of information — tasks, jobs by stage, open orders, cycle progress, or your end-of-day prompt. Widget order is customizable by dragging. Widgets update in real time as work moves through the board.","side":"right"}}]}"""
        });

        // ── Field Reference (QuickRef) ───────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Dashboard Field Reference",
            Slug = "dashboard-field-reference",
            Summary = "Complete reference for every widget, indicator, action, and behavior on the Dashboard.",
            ContentType = TrainingContentType.QuickRef,
            EstimatedMinutes = 4,
            IsPublished = true,
            SortOrder = 3,
            AppRoutes = """["/dashboard"]""",
            Tags = """["dashboard","reference"]""",
            ContentJson = """{"title":"Dashboard Field Reference","groups":[{"heading":"Today's Tasks Widget","items":[{"label":"Job List","value":"Shows your assigned jobs sorted by due date (earliest first). Each row displays the job title, due date, priority indicator, and current stage."},{"label":"Overdue Highlight","value":"Jobs past their due date are highlighted with a red/error color so they stand out from upcoming tasks."},{"label":"Click Action","value":"Click any job row to open the job detail dialog. From there you can view subtasks, files, activity, and take actions."},{"label":"Empty State","value":"When you have no assigned tasks, the widget shows an empty state message with an icon."}]},{"heading":"End of Day Widget","items":[{"label":"Top 3 Prompt","value":"A textarea prompting you to capture your Top 3 priorities for tomorrow. Type your priorities and save them at the end of your day."},{"label":"Save Button","value":"Saves your end-of-day response. Once saved, the widget switches to a confirmation view showing what you entered."},{"label":"Saved State","value":"After saving, the widget shows your recorded response with a check icon and an Edit button to revise it."},{"label":"Edit Action","value":"Click Edit on the saved view to return to the textarea and update your Top 3 for tomorrow."}]},{"heading":"Open Orders Widget","items":[{"label":"Total Count","value":"Shows the total number of open sales orders as a single headline number."},{"label":"Stage Breakdown","value":"Breaks the open orders down by Confirmed, In Production, and Partially Shipped counts, giving a pipeline overview."},{"label":"View All Link","value":"A 'View all orders' link navigates to the Sales Orders page for the full list."}]},{"heading":"Cycle Progress Widget","items":[{"label":"Progress Bar","value":"Horizontal bar showing the percentage of current planning cycle entries completed."},{"label":"Overdue Status","value":"A status chip shows the days remaining in the cycle, switching to an 'Overdue' label when the cycle has run past its end date."},{"label":"Progress Label","value":"Shows completed vs total entries with the exact completion percentage, e.g. '3/8 (38%)'."},{"label":"Entry List & Link","value":"Lists the first few cycle entries with completion checkmarks; the cycle name and a 'more' link navigate to the Planning page for full detail."}]},{"heading":"Jobs by Stage Widget","items":[{"label":"Stage Bars","value":"A horizontal bar per board stage, with the bar length scaled to each stage's job count relative to the busiest stage."},{"label":"Stage Counts","value":"Each row shows the stage label and the number of jobs currently sitting in that stage."},{"label":"At-a-Glance Pipeline","value":"Lets you see where work is concentrated across the board without opening the Kanban view."}]},{"heading":"Getting Started Banner","items":[{"label":"Onboarding Checklist","value":"Tracks setup progress with steps like create your first job, add a customer, set up track types, receive first stock, and explore reports. Steps are filtered to the capabilities your install has enabled."},{"label":"Dismiss Behavior","value":"The banner hides automatically once enough steps are complete, and can also be dismissed manually with the close button (the dismissal is saved to your preferences)."}]},{"heading":"Team Load Widget","items":[{"label":"Member Rows","value":"One row per team member with their avatar and name, showing how work is distributed across the team."},{"label":"Workload Bar","value":"A horizontal bar per member filled in proportion to their task count against their capacity."},{"label":"Task Count","value":"A numeric count of the member's current tasks shown alongside the bar."}]},{"heading":"KPI Chips","items":[{"label":"Metrics Displayed","value":"A fixed strip of chips at the top of the dashboard showing your active job count, overdue count, and total hours, each with a trend change indicator."},{"label":"Visual Style","value":"Small chips using the KpiChipComponent. Each shows a value, label, and change direction; the overdue chip uses the warn color. The strip appears only when the jobs module is enabled."}]},{"heading":"Layout and Preferences","items":[{"label":"Drag to Rearrange","value":"Grab any widget by its header and drag to reposition. The grid snaps widgets into place."},{"label":"Layout Persistence","value":"Your widget arrangement is saved to user preferences (localStorage + API). Restored on login from any device."},{"label":"Grid System","value":"Powered by gridstack. Widgets have default sizes but can be rearranged freely within the grid."}]},{"heading":"Loading Behavior","items":[{"label":"Initial Load","value":"Dashboard uses LoadingService global overlay while fetching data from multiple endpoints. The overlay clears once all widget data is ready."},{"label":"No Partial Loading","value":"All widgets load together behind the overlay — you see the complete dashboard at once, no flickering or progressive rendering."}]}]}"""
        });

        // ── Knowledge Check (Quiz) ───────────────────────────────────────
        await GetOrCreateModule(new TrainingModule
        {
            Title = "Dashboard Knowledge Check",
            Slug = "dashboard-quiz",
            Summary = "Test your knowledge of the Dashboard: widgets, layout customization, end-of-day prompt, tasks, and cycle progress.",
            ContentType = TrainingContentType.Quiz,
            EstimatedMinutes = 5,
            IsPublished = true,
            SortOrder = 4,
            AppRoutes = """["/dashboard"]""",
            Tags = """["dashboard","quiz"]""",
            ContentJson = """{"passingScore":80,"questionsPerQuiz":8,"shuffleOptions":true,"showExplanationsAfterSubmit":true,"questions":[{"id":"db1","text":"You log in to QB Engineer and see a loading overlay before the Dashboard appears. Why does the Dashboard load this way?","options":[{"id":"a","text":"The Dashboard is slow because it renders 3D graphics"},{"id":"b","text":"It uses a global loading overlay because it fetches data from multiple endpoints simultaneously — all widgets load together behind the overlay","isCorrect":true},{"id":"c","text":"Each widget loads independently with its own spinner"},{"id":"d","text":"The loading overlay is a bug — the Dashboard should load instantly from cache"}],"explanation":"The Dashboard uses LoadingService (global overlay) because it fetches data from multiple API endpoints at once. The overlay clears when all data is ready, so you see the complete dashboard without partial loading or flickering."},{"id":"db2","text":"You see a job highlighted in red in the Today's Tasks widget. What does this mean?","options":[{"id":"a","text":"The job has been flagged as high priority by a manager"},{"id":"b","text":"The job's due date has passed — it's overdue","isCorrect":true},{"id":"c","text":"The job is blocked by a hold and cannot proceed"},{"id":"d","text":"The job was recently assigned to you and hasn't been viewed yet"}],"explanation":"Overdue jobs (past their due date) are highlighted with red/error coloring in the Today's Tasks widget so they stand out from upcoming tasks and get immediate attention."},{"id":"db3","text":"You rearrange your Dashboard widgets by dragging them to new positions. What happens to your layout?","options":[{"id":"a","text":"It resets to default when you refresh the page"},{"id":"b","text":"It's saved to your user preferences and persists across sessions and devices","isCorrect":true},{"id":"c","text":"It's only saved in the current browser tab"},{"id":"d","text":"You need to click a Save Layout button to persist changes"}],"explanation":"Widget positions are saved automatically to user preferences (localStorage + API). Your layout is restored when you log in from any device — no manual save needed."},{"id":"db4","text":"The Cycle Progress bar has turned yellow. What does this indicate?","options":[{"id":"a","text":"The planning cycle has been paused by an admin"},{"id":"b","text":"You're ahead of schedule and have extra capacity"},{"id":"c","text":"You're behind schedule — completion percentage is lower than expected for the elapsed time","isCorrect":true},{"id":"d","text":"The cycle ends today and you should start planning the next one"}],"explanation":"The progress bar turns yellow when your completion rate is behind where it should be given how much of the cycle has elapsed. This is a visual cue to prioritize cycle items."},{"id":"db5","text":"You want to record your Top 3 priorities for tomorrow from the Dashboard. How?","options":[{"id":"a","text":"Navigate to the Planning page and add them to the next cycle"},{"id":"b","text":"Type them into the End of Day widget's textarea and click Save","isCorrect":true},{"id":"c","text":"They are generated automatically — you can't enter them yourself"},{"id":"d","text":"You can only enter them from the job's detail panel"}],"explanation":"The End of Day widget prompts you to capture your Top 3 for tomorrow. Type them into the textarea and click Save; the widget then shows your saved response with an Edit button to revise it later."},{"id":"db6","text":"You click a job in the Today's Tasks widget. What happens?","options":[{"id":"a","text":"The job's Kanban card is highlighted on the board"},{"id":"b","text":"The job detail dialog opens, showing subtasks, files, activity log, and available actions","isCorrect":true},{"id":"c","text":"A summary tooltip appears with the job title and due date"},{"id":"d","text":"You're navigated to the Backlog page with that job selected"}],"explanation":"Clicking a job in Today's Tasks opens the full job detail dialog. From there you can view and manage subtasks, files, activity history, and take actions like updating status."},{"id":"db7","text":"A new employee logs in and sees a 'Getting Started' banner on their Dashboard. When does this banner disappear?","options":[{"id":"a","text":"After 7 days, regardless of progress"},{"id":"b","text":"When the employee clicks 'Dismiss' on the banner"},{"id":"c","text":"When all onboarding steps are complete — profile, compliance forms, training","isCorrect":true},{"id":"d","text":"It never disappears — it transforms into a regular widget"}],"explanation":"The Getting Started banner tracks onboarding progress and disappears automatically once all steps are complete. It cannot be manually dismissed while onboarding steps remain."},{"id":"db8","text":"You glance at the Jobs by Stage widget. What does the length of each bar represent?","options":[{"id":"a","text":"How long jobs have been sitting in that stage"},{"id":"b","text":"The number of jobs in that stage, scaled against the busiest stage","isCorrect":true},{"id":"c","text":"The total dollar value of jobs in that stage"},{"id":"d","text":"How overdue the jobs in that stage are"}],"explanation":"The Jobs by Stage widget draws one bar per board stage, with each bar's length proportional to that stage's job count relative to the busiest stage. The count is also shown numerically beside each bar."},{"id":"db9","text":"The Inventory Snapshot widget shows a non-zero low-stock count highlighted in alert color. What is it telling you?","options":[{"id":"a","text":"That many parts are missing a description"},{"id":"b","text":"That some parts have dropped to or below their minimum stock threshold","isCorrect":true},{"id":"c","text":"That inventory counts haven't been reconciled this month"},{"id":"d","text":"That new stock has just been received"}],"explanation":"The Inventory Snapshot widget shows part count, total on-hand, and a low-stock count. When parts fall to or below their minimum threshold, the low-stock figure is highlighted and the affected parts are listed with their current vs minimum quantities."},{"id":"db10","text":"How are jobs ordered in the Today's Tasks widget?","options":[{"id":"a","text":"Alphabetically by job title"},{"id":"b","text":"By status priority — overdue first, then active, upcoming, and completed","isCorrect":true},{"id":"c","text":"By creation date — newest first"},{"id":"d","text":"Randomly each time the page loads"}],"explanation":"Today's Tasks orders jobs by their status: overdue items come first so they get immediate attention, followed by active, upcoming, and completed. The widget shows the top several and surfaces an overdue alert banner when any are past due."},{"id":"db11","text":"You want to see how many sales orders are currently in production. Where do you look on the Dashboard?","options":[{"id":"a","text":"The KPI chips at the top of the page"},{"id":"b","text":"The Open Orders widget — it breaks the open-order total down by Confirmed, In Production, and Partially Shipped","isCorrect":true},{"id":"c","text":"The Today's Tasks widget — count the items manually"},{"id":"d","text":"The Cycle Progress widget — it breaks down by stage"}],"explanation":"The Open Orders widget shows the total open sales orders plus a breakdown by Confirmed, In Production, and Partially Shipped. Look at the In Production count for your answer."},{"id":"db12","text":"The Action Items widget lists a follow-up task. What two quick actions can you take on it directly from the widget?","options":[{"id":"a","text":"Reassign it or change its priority"},{"id":"b","text":"Complete it (check) or dismiss it (close)","isCorrect":true},{"id":"c","text":"Print it or export it to PDF"},{"id":"d","text":"Snooze it or escalate it to a manager"}],"explanation":"Each Action Items row has a check button to complete the task and a close button to dismiss it, so you can clear follow-ups without leaving the dashboard. When the list is empty the widget shows an empty state."}]}"""
        });

        Log.Information("Seeded Dashboard training modules");
    }
}
